    43	
    44	static inline void updateCrcChecksum2(int xlen,
    45	                                      int ylen,
    46	                                      uint8_t crcChecksum[xlen][ylen],
    47	                                      int gxlen,
    48	                                      int gylen,
    49	                                      uint8_t crcGen[gxlen][gylen],
    50	                                      uint8_t listSize,
    51	                                      uint32_t i2,
    52	                                      uint8_t len)
    53	{
    54	  for (uint8_t i = 0; i < listSize; i++) {
    55	    for (uint8_t j = 0; j < len; j++) {
    56	      crcChecksum[j][i+listSize] = ( (crcChecksum[j][i] + crcGen[i2][j]) % 2 );
    57	    }
    58	  }
    59	}
