    61	int8_t polar_decoder(double *input,
    62	                     uint32_t *out,
    63	                     uint8_t listSize,
    64	                     int8_t messageType,
    65	                     uint16_t messageLength,
    66	                     uint8_t aggregation_level
    67	                     )
    68	{
    69	  t_nrPolar_params *polarParams=nr_polar_params(messageType, messageLength, aggregation_level, true);
    70	  //Assumes no a priori knowledge.
    71	  uint8_t bit[polarParams->N][polarParams->n+1][2*listSize];
    72	  memset(bit,0,sizeof bit);
    73	  uint8_t bitUpdated[polarParams->N][polarParams->n+1]; //0=False, 1=True
    74	  memset(bitUpdated,0,sizeof bitUpdated);
    75	  uint8_t llrUpdated[polarParams->N][polarParams->n+1]; //0=False, 1=True
    76	  memset(llrUpdated,0,sizeof llrUpdated);
    77	  double  llr[polarParams->N][polarParams->n+1][2*listSize];
    78	  uint8_t crcChecksum[polarParams->crcParityBits][2*listSize];
    79	  memset(crcChecksum,0,sizeof crcChecksum);
    80	  double  pathMetric[2*listSize];
    81	  uint8_t crcState[2*listSize]; //0=False, 1=True
    82	
    83	  for (int i=0; i<(2*listSize); i++) {
    84	    pathMetric[i] = 0;
    85	    crcState[i]=1;
    86	  }
    87	
    88	  for (int i=0; i<polarParams->N; i++) {
    89	    llrUpdated[i][polarParams->n]=1;
    90	    bitUpdated[i][0]=((polarParams->information_bit_pattern[i]+1) % 2);
    91	  }
    92	
    93	  uint8_t extended_crc_generator_matrix[polarParams->K][polarParams->crcParityBits]; //G_P3
    94	  uint8_t tempECGM[polarParams->K][polarParams->crcParityBits]; //G_P2
    95	
    96	  for (int i=0; i<polarParams->payloadBits; i++) {
    97	    for (int j=0; j<polarParams->crcParityBits; j++) {
    98	      tempECGM[i][j]=polarParams->crc_generator_matrix[i][j];
    99	    }
   100	  }
   101	
   102	  for (int i=polarParams->payloadBits; i<polarParams->K; i++) {
   103	    for (int j=0; j<polarParams->crcParityBits; j++) {
   104	      if( (i-polarParams->payloadBits) == j ) {
   105	        tempECGM[i][j]=1;
   106	      } else {
   107	        tempECGM[i][j]=0;
   108	      }
   109	    }
   110	  }
   111	
   112	  for (int i=0; i<polarParams->K; i++) {
   113	    for (int j=0; j<polarParams->crcParityBits; j++) {
   114	      extended_crc_generator_matrix[i][j]=tempECGM[polarParams->interleaving_pattern[i]][j];
   115	    }
   116	  }
   117	
   118	  //The index of the last 1-valued bit that appears in each column.
   119	  uint16_t last1ind[polarParams->crcParityBits];
   120	
   121	  for (int j=0; j<polarParams->crcParityBits; j++) {
   122	    for (int i=0; i<polarParams->K; i++) {
   123	      if (extended_crc_generator_matrix[i][j]==1) last1ind[j]=i;
   124	    }
   125	  }
   126	
   127	  double d_tilde[polarParams->N];
   128	  nr_polar_rate_matching(input, d_tilde, polarParams->rate_matching_pattern, polarParams->K, polarParams->N, polarParams->encoderLength);
   129	
   130	  for (int j = 0; j < polarParams->N; j++) llr[j][polarParams->n][0]=d_tilde[j];
   131	
   132	  /*
   133	   * SCL polar decoder.
   134	   */
   135	  uint32_t nonFrozenBit=0;
   136	  uint8_t currentListSize=1;
   137	  uint8_t decoderIterationCheck=0;
   138	  int16_t checkCrcBits=-1;
   139	  uint8_t listIndex[2*listSize], copyIndex;
   140	
   141	  for (uint16_t currentBit=0; currentBit<polarParams->N; currentBit++) {
   142	    updateLLR(currentListSize, currentBit, 0, polarParams->N, polarParams->n+1, 2*listSize, llr, llrUpdated, bit, bitUpdated);
   143	
   144	    if (polarParams->information_bit_pattern[currentBit]==0) { //Frozen bit.
   145	      updatePathMetric(pathMetric, currentListSize, 0, currentBit, polarParams->N, polarParams->n+1, 2*listSize, llr);
   146	    } else { //Information or CRC bit.
   147	      updatePathMetric2(pathMetric, currentListSize, currentBit, polarParams->N, polarParams->n+1, 2*listSize, llr);
   148	
   149	      for (int i = 0; i < currentListSize; i++) {
   150	      for (int j = 0; j < polarParams->N; j++) {
   151	        for (int k = 0; k < (polarParams->n+1); k++) {
   152	            bit[j][k][i+currentListSize]=bit[j][k][i];
   153	            llr[j][k][i+currentListSize]=llr[j][k][i];
   154	          }
   155	        }
   156	      }
   157	
   158	        for (int i = 0; i < currentListSize; i++) {
   159	          bit[currentBit][0][i]=0;
   160	          crcState[i+currentListSize]=crcState[i];
   161	        }
   162	
   163	      for (int i = currentListSize; i < 2*currentListSize; i++) bit[currentBit][0][i]=1;
   164	
   165	      bitUpdated[currentBit][0]=1;
   166	      updateCrcChecksum2(polarParams->crcParityBits, 2*listSize, crcChecksum,
   167	                         polarParams->K, polarParams->crcParityBits, extended_crc_generator_matrix, 
   168	                         currentListSize, nonFrozenBit, polarParams->crcParityBits);
   169	      currentListSize*=2;
   170	
   171	      //Keep only the best "listSize" number of entries.
   172	      if (currentListSize > listSize) {
   173	        for (uint8_t i = 0; i < 2*listSize; i++) listIndex[i]=i;
   174	
   175	        nr_sort_asc_double_1D_array_ind(pathMetric, listIndex, currentListSize);
   176	        //sort listIndex[listSize, ..., 2*listSize-1] in descending order.
   177	        uint8_t swaps, tempInd;
   178	
   179	        for (uint8_t i = 0; i < listSize; i++) {
   180	          swaps = 0;
   181	
   182	          for (uint8_t j = listSize; j < (2*listSize - i) - 1; j++) {
   183	            if (listIndex[j+1] > listIndex[j]) {
   184	              tempInd = listIndex[j];
   185	              listIndex[j] = listIndex[j + 1];
   186	              listIndex[j + 1] = tempInd;
   187	              swaps++;
   188	            }
   189	          }
   190	
   191	          if (swaps == 0)
   192	            break;
   193	        }
   194	
   195	        //First, backup the best "listSize" number of entries.
   196	        for (int k=(listSize-1); k>0; k--) {
   197	          for (int i=0; i<polarParams->N; i++) {
   198	            for (int j=0; j<(polarParams->n+1); j++) {
   199	              bit[i][j][listIndex[(2*listSize-1)-k]]=bit[i][j][listIndex[k]];
   200	              llr[i][j][listIndex[(2*listSize-1)-k]]=llr[i][j][listIndex[k]];
   201	            }
   202	          }
   203	        }
   204	
   205	        for (int k=(listSize-1); k>0; k--) {
   206	          for (int i = 0; i < polarParams->crcParityBits; i++) {
   207	            crcChecksum[i][listIndex[(2*listSize-1)-k]] = crcChecksum[i][listIndex[k]];
   208	          }
   209	        }
   210	
   211	        for (int k=(listSize-1); k>0; k--) crcState[listIndex[(2*listSize-1)-k]]=crcState[listIndex[k]];
   212	
   213	        //Copy the best "listSize" number of entries to the first indices.
   214	        for (int k = 0; k < listSize; k++) {
   215	          if (k > listIndex[k]) {
   216	            copyIndex = listIndex[(2*listSize-1)-k];
   217	          } else { //Use the backup.
   218	            copyIndex = listIndex[k];
   219	          }
   220	
   221	          for (int i = 0; i < polarParams->N; i++) {
   222	            for (int j = 0; j < (polarParams->n + 1); j++) {
   223	              bit[i][j][k] = bit[i][j][copyIndex];
   224	              llr[i][j][k] = llr[i][j][copyIndex];
   225	            }
   226	          }
   227	        }
   228	
   229	        for (int k = 0; k < listSize; k++) {
   230	          if (k > listIndex[k]) {
   231	            copyIndex = listIndex[(2*listSize-1)-k];
   232	          } else { //Use the backup.
   233	            copyIndex = listIndex[k];
   234	          }
   235	
   236	          for (int i = 0; i < polarParams->crcParityBits; i++) {
   237	            crcChecksum[i][k]=crcChecksum[i][copyIndex];
   238	          }
   239	        }
   240	
   241	        for (int k = 0; k < listSize; k++) {
   242	          if (k > listIndex[k]) {
   243	            copyIndex = listIndex[(2*listSize-1)-k];
   244	          } else { //Use the backup.
   245	            copyIndex = listIndex[k];
   246	          }
   247	
   248	          crcState[k]=crcState[copyIndex];
   249	        }
   250	
   251	        currentListSize = listSize;
   252	      }
   253	
   254	      for (int i=0; i<polarParams->crcParityBits; i++) {
   255	        if (last1ind[i]==nonFrozenBit) {
   256	          checkCrcBits=i;
   257	          break;
   258	        }
   259	      }
   260	
   261	      if ( checkCrcBits > (-1) ) {
   262	        for (uint8_t i = 0; i < currentListSize; i++) {
   263	          if (crcChecksum[checkCrcBits][i]==1) {
   264	            crcState[i]=0; //0=False, 1=True
   265	          }
   266	        }
   267	      }
   268	
   269	      for (uint8_t i = 0; i < currentListSize; i++) decoderIterationCheck+=crcState[i];
   270	
   271	      if (decoderIterationCheck==0) {
   272	        //perror("[SCL polar decoder] All list entries have failed the CRC checks.");
   273	        polarReturn(-1);
   274	      }
   275	
   276	      nonFrozenBit++;
   277	      decoderIterationCheck=0;
   278	      checkCrcBits=-1;
   279	    }
   280	  }
   281	
   282	  for (uint8_t i = 0; i < 2*listSize; i++) listIndex[i]=i;
   283	
   284	  nr_sort_asc_double_1D_array_ind(pathMetric, listIndex, currentListSize);
   285	
   286	  for (uint8_t i = 0; i < fmin(listSize, (pow(2,polarParams->crcCorrectionBits)) ); i++) {
   287	    if ( crcState[listIndex[i]] == 1 ) {
   288	      for (int j = 0; j < polarParams->N; j++) polarParams->nr_polar_U[j]=bit[j][0][listIndex[i]];
   289	
   290	      //Extract the information bits (û to ĉ)
   291	      nr_polar_info_bit_extraction(polarParams->nr_polar_U, polarParams->nr_polar_CPrime, polarParams->information_bit_pattern, polarParams->N);
   292	      //Deinterleaving (ĉ to b)
   293	      nr_polar_deinterleaver(polarParams->nr_polar_CPrime, polarParams->nr_polar_B, polarParams->interleaving_pattern, polarParams->K);
   294	
   295	      //Remove the CRC (â)
   296	      for (int j = 0; j < polarParams->payloadBits; j++) polarParams->nr_polar_A[j]=polarParams->nr_polar_B[j];
   297	
   298	      break;
   299	    }
   300	  }
   301	
   302	  /*
   303	   * Return bits.
   304	   */
   305	  nr_byte2bit_uint8_32(polarParams->nr_polar_A, polarParams->payloadBits, out);
   306	
   307	  polarReturn 0;
   308	}
